+import React, { useState, useEffect } from 'react';
+import api from '../utils/api';
+import toast from 'react-hot-toast';
+import { FiEye, FiDownload } from 'react-icons/fi';
+import * as XLSX from 'xlsx';
+import Receipt from './Receipt';
+import { formatDateTime } from '../utils/dateHelper';
+
+const SalesHistory = () => {
+  const [transactions, setTransactions] = useState([]);
+  const [filterDate, setFilterDate] = useState('');
+  const [selectedTransaction, setSelectedTransaction] = useState(null);
+  const [showReceipt, setShowReceipt] = useState(false);
+
+  useEffect(() => {
+    fetchTransactions();
+  }, []);
+
+  const fetchTransactions = async (date = '') => {
+    try {
+      const url = date ? `/transactions?date=${date}` : '/transactions';
+      const res = await api.get(url);
+      setTransactions(res.data);
+    } catch (error) {
+      toast.error('Failed to load transactions');
+    }
+  };
+
+  const handleFilter = () => fetchTransactions(filterDate);
+
+  // تصدير إلى Excel
+  const exportToExcel = () => {
+    if (transactions.length === 0) {
+      toast.error('No data to export');
+      return;
+    }
+
+    // تجهيز البيانات
+    const data = transactions.map(t => ({
+      ID: t.id,
+      Date: new Date(t.created_at).toLocaleString(),
+      Items: t.items?.length || 0,
+      'Total ($)': t.total,
+      Payment: t.payment_method === 'cash' ? 'Cash' : 'Card',
+      Cashier: t.cashier_name,
+      Discount: t.discount || 0,
+      Tax: t.tax || 0,
+    }));
+
+    const ws = XLSX.utils.json_to_sheet(data);
+    const wb = XLSX.utils.book_new();
+    XLSX.utils.book_append_sheet(wb, ws, 'Sales');
+    XLSX.writeFile(wb, `sales_${new Date().toISOString().slice(0,10)}.xlsx`);
+    toast.success('Exported successfully');
+  };
+
+  return (
+    <div className="space-y-6">
+      <div className="flex justify-between items-center">
+        <h1 className="text-2xl font-bold text-gray-800">Sales History</h1>
+        <button onClick={exportToExcel} className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2">
+          <FiDownload /> Export to Excel
+        </button>
+      </div>
+
+      {/* شريط التصفية */}
+      <div className="bg-white rounded-xl shadow-md p-4 flex flex-wrap gap-4 items-end">
+        <div>
+          <label className="input-label">Filter by Date</label>
+          <input
+            type="date"
+            value={filterDate}
+            onChange={(e) => setFilterDate(e.target.value)}
+            className="input-field"
+          />
+        </div>
+        <button onClick={handleFilter} className="btn-primary px-6">Apply</button>
+        {filterDate && (
+          <button onClick={() => { setFilterDate(''); fetchTransactions(); }} className="btn-outline px-6">Clear</button>
+        )}
+      </div>
+
+      {/* جدول المعاملات */}
+      <div className="bg-white rounded-xl shadow-md overflow-hidden">
+        <div className="overflow-x-auto">
+          <table className="min-w-full">
+            <thead className="bg-gray-50">
+              <tr>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">ID</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Date</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Items</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Total</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Payment</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
+              </tr>
+            </thead>
+            <tbody className="divide-y divide-gray-200">
+              {transactions.map(t => (
+                <tr key={t.id}>
+                  <td className="px-6 py-4">#{t.id}</td>
+                  <td>{formatDateTime(t.created_at)}</td>
+                  <td className="px-6 py-4">{t.items?.length || 0}</td>
+                  <td className="px-6 py-4 font-semibold text-green-600">${t.total.toFixed(2)}</td>
+                  <td className="px-6 py-4 capitalize">{t.payment_method}</td>
+                  <td className="px-6 py-4">
+                    <button
+                      onClick={() => { setSelectedTransaction(t); setShowReceipt(true); }}
+                      className="text-blue-600 hover:text-blue-800 flex items-center gap-1"
+                    >
+                      <FiEye size={16} /> View
+                    </button>
+                  </td>
+                </tr>
+              ))}
+            </tbody>
+          </table>
+        </div>
+      </div>
+
+      {/* نافذة الإيصال */}
+      {showReceipt && selectedTransaction && (
+        <Receipt transaction={selectedTransaction} onClose={() => setShowReceipt(false)} />
+      )}
+    </div>
+  );
+};
+
+export default SalesHistory;
